const store = $getWorkflowStaticData('global');       // memória
const sid   = items[0].json.sessionId;                // id da conversa

// ── Normaliza: se veio do Router, o route está em output.route
if (items[0].json.output?.route) {
  items[0].json.route = items[0].json.output.route;   // coloca na raiz
}

// ── 1) GRAVAR ──
if (items[0].json.route) {          // só existe quando veio do Router
  store[sid] = items[0].json.route; // ex.: "PRODUCT" / "TINTOMETRIC"
}

// ── 2) APAGAR ──
if (items[0].json.finished === true) { // agente sinalizou fim
  delete store[sid];
}

return items;   // importante!

